15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.numeric_std.all;
18	use ieee.math_real.all;
19	
20	package StdRtlPkg is
21	
22	   -- Useful for pre compiler
23	   constant IN_SIMULATION_C : boolean := false
24	-- pragma translate_off
25	                                         or true
26	-- pragma translate_on
27	;
28	   constant IN_SYNTHESIS_C : boolean := not(IN_SIMULATION_C);
29	
30	   -- Typing std_logic(_vector) is annoying
31	   subtype sl is std_logic;
32	   subtype slv is std_logic_vector;
33	
34	   -- Declare arrays of built in types
35	   --type SlvArray     is array (natural range <>) of slv;   -- not supported in VCS yet (14APRIL2014 -- LLR)
36	   type IntegerArray is array (natural range <>) of integer;
37	   type NaturalArray is array (natural range <>) of natural;
38	   type PositiveArray is array (natural range <>) of positive;
39	   type RealArray is array (natural range <>) of real;
40	   type TimeArray is array (natural range <>) of time;
41	   type BooleanArray is array (natural range <>) of boolean;
42	
43	   -- Declare vector arrays of built in types
44	   --type SlvVectorArray     is array (natural range<>, natural range<>) of slv;   -- not supported in VCS yet (14APRIL2014 -- LLR)
45	   type IntegerVectorArray is array (natural range<>, natural range<>) of integer;
46	   type NaturalVectorArray is array (natural range<>, natural range<>) of natural;
47	   type PositiveVectorArray is array (natural range<>, natural range<>) of positive;
48	   type RealVectorArray is array (natural range<>, natural range<>) of real;
49	   type TimeVectorArray is array (natural range<>, natural range<>) of time;
50	   type BooleanVectorArray is array (natural range<>, natural range<>) of boolean;
51	
52	   -- Create an arbitrary sized slv with all bits set high or low
53	   function slvAll (size  : positive; value : sl) return slv;
54	   function slvZero (size : positive) return slv;
55	   function slvOne (size  : positive) return slv;
56	
57	   -- Very useful functions
58	   function isPowerOf2 (number       : natural) return boolean;
59	   function isPowerOf2 (vector       : slv) return boolean;
60	   function log2 (constant number    : integer) return natural;
61	   function logB (base               : natural; number : natural) return natural;
62	   function bitSize (constant number : natural) return positive;
63	   function bitReverse (a            : slv) return slv;
64	   function wordCount (number        : positive; wordSize : positive := 8) return natural;
65	   function endianSwap(vector        : slv) return slv;
66	
67	   -- Similar to python's range() function
68	   function list (constant start, size, step : integer) return IntegerArray;
69	
70	   -- Simple decoder and mux functions
71	   function decode(v    : slv) return slv;
72	   function genmux(s, v : slv) return sl;
73	
74	   -- This should be unnecessary in VHDL 2008
75	   function toBoolean (logic    : sl) return boolean;
76	   function toSl (bool          : boolean) return sl;
77	   function toString (bool      : boolean) return string;
78	   function toBoolean (str      : string) return boolean;
79	   function toSlv(bools         : BooleanArray) return slv;
80	   function toBooleanArray (vec : slv) return BooleanArray;
81	
82	   -- Unary reduction operators, also unnecessary in VHDL 2008
83	   function uOr (vec  : slv) return sl;
84	   function uAnd (vec : slv) return sl;
85	   function uXor (vec : slv) return sl;
86	
87	   -- Test if all bits in a vector are set to a given logic value
88	   function allBits (vec : slv; test : sl) return boolean;
89	   function noBits (vec  : slv; test : sl) return boolean;
90	
91	   -- These just use uXor to calculate parity
92	   -- Output is parity bit value needed to achieve that parity given vec.
93	   function evenParity (vec : slv) return sl;
94	   function oddParity (vec  : slv) return sl;
95	
96	   -- Functions for counting the number of '1' in a slv bus
97	   function onesCountU (vec : slv) return unsigned;
98	   function onesCount (vec  : slv) return slv;
99	
100	   -- Gray Code functions
101	   function grayEncode (vec : unsigned) return unsigned;
102	   function grayEncode (vec : slv) return slv;
103	   function grayDecode (vec : unsigned) return unsigned;
104	   function grayDecode (vec : slv) return slv;
105	
106	   -- Linear Feedback Shift Register function
107	   function lfsrShift (lfsr : slv; constant taps : NaturalArray; input : sl := '0') return slv;
108	
109	   function maximum (left, right : integer) return integer;
110	   function maximum (a           : IntegerArray) return integer;
111	   function minimum (left, right : integer) return integer;
112	   function minimum (a           : IntegerArray) return integer;
113	   function sort (a              : IntegerArray) return IntegerArray;
114	   function median (a            : IntegerArray) return integer;
115	
116	   -- One line if-then-else functions. Useful for assigning constants based on generics.
117	   function ite(i : boolean; t : boolean; e : boolean) return boolean;
118	   function ite(i : boolean; t : sl; e : sl) return sl;
119	   function ite(i : boolean; t : slv; e : slv) return slv;
120	   function ite(i : boolean; t : bit; e : bit) return bit;
121	   function ite(i : boolean; t : bit_vector; e : bit_vector) return bit_vector;
122	   function ite(i : boolean; t : character; e : character) return character;
123	   function ite(i : boolean; t : string; e : string) return string;
124	   function ite(i : boolean; t : integer; e : integer) return integer;
125	   function ite(i : boolean; t : real; e : real) return real;
126	   function ite(i : boolean; t : time; e : time) return time;
127	
128	   -- conv_std_logic_vector functions
129	   function toSlv(ARG : integer; SIZE : integer) return slv;
130	
131	   -- gets real multiplication and division with integers
132	   function "*" (L : integer; R : real) return real;
133	   function "*" (L : real; R : integer) return real;
134	   function "/" (L : integer; R : real) return real;
135	   function "/" (L : real; R : integer) return real;
136	
137	   function adcConversion (ain : real; low : real; high : real; bits : positive; twosComp : boolean) return slv;
138	
139	   --gets a time ratio
140	   function getTimeRatio (T1, T2 : time) return natural;  --not supported by Vivado
141	   function getTimeRatio (T1, T2 : real) return natural;
142	
143	   procedure assignSlv (i    : inout integer; vector : inout slv; value : in slv);
144	   procedure assignSlv (i    : inout integer; vector : inout slv; value : in sl);
145	   procedure assignRecord (i : inout integer; vector : in slv; value : inout slv);
146	   procedure assignRecord (i : inout integer; vector : in slv; value : inout sl);
147	
148	   -- Resize vector types, either by trimming or padding upper indicies
149	   function resize (vec : slv; newSize : integer; pad : sl           := '0') return slv;
150	   function resize (str : string; newSize : integer; pad : character := nul) return string;
151	
152	   -- Match Functions
153	   function StdMatch (L, R : std_ulogic) return boolean;
154	   function StdMatch (L, R : unsigned) return boolean;
155	   function StdMatch (L, R : signed) return boolean;
156	   function StdMatch (L, R : slv) return boolean;
