158	   -- Some synthesis tools wont accept unit types
159	   -- pragma translate_off
160	   type frequency is range 0 to 2147483647
161	      units
162	         Hz;
163	         kHz = 1000 Hz;
164	         MHz = 1000 kHz;
165	         GHz = 1000 MHz;
166	      end units;
167	
168	   function toTime(f : frequency) return time;
