745	   -- Function: log2
746	   -- Purpose: Finds the log base 2 of an integer
747	   -- Input is rounded up to nearest power of two.
748	   -- Therefore log2(5) = log2(8) = 3.
749	   -- Arg: number - integer to find log2 of
750	   -- Returns: Integer containing log base two of input.
751	   ---------------------------------------------------------------------------------------------------------------------
752	   function log2(constant number : integer) return natural is
753	   begin
754	      if (number < 2) then
755	         return 1;
756	      end if;
757	      return integer(ceil(ieee.math_real.log2(real(number))));
758	   end function;
759	
760	   ---------------------------------------------------------------------------------------------------------------------
761	   -- Function: logB
762	   -- Purpose: Finds the log arbitrary base of an integer
763	   -- output is rounded up to nearest integer
764	   --    logB(3, 8) --> ceil(log3(8)) == 2
765	   -- Arg: base   - arbitrary base for log
766	   --    : number - integer to find log arbitrary base of
767	   -- Returns: Integer ceil(log(base, number))
768	   ---------------------------------------------------------------------------------------------------------------------
769	   function logB (base : natural; number : natural) return natural is
770	   begin
771	      if number <= base then
772	         return 1;
773	      else
774	         return logB(base, number/base) + 1;
775	      end if;
776	   end function logB;
