1070	   -- Get the binary equivalent of a Gray code created with gray_encode.
1071	   function grayDecode (vec : unsigned)
1072	      return unsigned is
1073	      variable retVar : unsigned(vec'range) := (others => '0');
1074	   begin
1075	      for i in vec'range loop
1076	         if (i = vec'left) then
1077	            retVar(i) := vec(i);
1078	         else
1079	            if (vec'ascending) then
1080	               retVar(i) := retVar(i-1) xor vec(i);
1081	            else
1082	               retVar(i) := retVar(i+1) xor vec(i);
1083	            end if;
1084	         end if;
1085	      end loop;
1086	      return retVar;
1087	   end function;
