1097	   -- Implements an N tap linear feedback shift operation
1098	   -- Size of LFSR is variable and determined by length of lfsr parameter
1099	   -- Number of taps is variable and determined by length of taps array parameter
1100	   -- An input parameter is also available for use in scramblers
1101	   -- Output is new lfsr value after one shift operation
1102	   -- The lfsr param can be indexed ascending or decending
1103	   -- The shift is in the direction of increasing index (left shift for decending, right for ascending)
1104	   -------------------------------------------------------------------------------------------------
1105	   function lfsrShift (lfsr : slv; constant taps : NaturalArray; input : sl := '0') return slv is
1106	      variable retVar : slv(lfsr'range) := (others => '0');
1107	   begin
1108	      if (lfsr'ascending) then
1109	         retVar := input & lfsr(lfsr'left to lfsr'right-1);
1110	      else
1111	         retVar := lfsr(lfsr'left-1 downto lfsr'right) & input;
1112	      end if;
1113	
1114	      for i in taps'range loop
1115	         assert (taps(i)  <= lfsr'high) report "lfsrShift() - Tap value exceedes lfsr range" severity failure;
1116	         retVar(lfsr'low) := retVar(lfsr'low) xor lfsr(taps(i));
1117	      end loop;
1118	
1119	      return retVar;
1120	   end function;
