1219	   -- simple insertion sort
1220	   function sort (
1221	      a : IntegerArray)
1222	      return IntegerArray is
1223	      variable sorted : IntegerArray(a'range) := a;
1224	      variable key    : integer;
1225	      variable j      : integer;
1226	   begin
1227	      for i in (a'low + 1) to a'high loop
1228	         key := sorted(i);
1229	         j   := i - 1;
1230	         while ((j >= a'low) and (sorted(j) > key)) loop
1231	            sorted(j + 1) := sorted(j);
1232	            j             := j - 1;
1233	         end loop;
1234	         sorted(j + 1) := key;
1235	      end loop;
1236	      return sorted;
1237	   end function sort;
