1256	   -- convert an integer to an STD_LOGIC_VECTOR
1257	   function toSlv(ARG : integer; SIZE : integer) return slv is
1258	   begin
1259	      if (ARG < 0) then
1260	         return slv(to_unsigned(0, SIZE));
1261	      end if;
1262	      return slv(to_unsigned(ARG, SIZE));
1263	   end function toSlv;
1264	
1265	
1266	   -------------------------------------------------------------------------------------------------
1267	   -- Multiply and divide reals and integer
1268	   -------------------------------------------------------------------------------------------------
1269	   function "*" (L : real; R : integer) return real is
1270	   begin
1271	      return real(L*real(R));
1272	   end function "*";
1273	
1274	   function "*" (L : integer; R : real) return real is
1275	   begin
1276	      return real(real(R)*L);
1277	   end function;
1278	
1279	   function "/" (L : integer; R : real) return real is
1280	   begin
1281	      return real(real(L)/R);
1282	   end function;
1283	
1284	   function "/" (L : real; R : integer) return real is
1285	   begin
1286	      return real(L/real(R));
1287	   end function;
1288	
1289	   -------------------------------------------------------------------------------------------------
1290	   -- Simulates an ADC conversion
1291	   -------------------------------------------------------------------------------------------------
1292	   function adcConversion (
1293	      ain      : real;
1294	      low      : real;
1295	      high     : real;
1296	      bits     : positive;
1297	      twosComp : boolean)
1298	      return slv is
1299	      variable tmpR : real;
1300	      variable tmpI : integer;
1301	
1302	      variable retSigned   : signed(bits-1 downto 0);
1303	      variable retUnsigned : unsigned(bits-1 downto 0);
1304	   begin
1305	      tmpR := ain;
1306	
1307	      -- Constrain input to full scale range
1308	      tmpR := realmin(high, tmpR);
1309	      tmpR := realmax(low, tmpR);
1310	
1311	      -- Scale to [0,1] or [-.5,.5]
1312	      tmpR := (tmpR-low)/(high-low) + ite(twosComp, -0.5, 0.0);
1313	
1314	      -- Scale to number of bits
1315	      tmpR := tmpR * real(2**bits);
1316	
1317	      if (twosComp) then
1318	         retSigned := to_signed(integer(round(tmpR)), bits);
1319	         return slv(retSigned);
1320	      else
1321	         retUnsigned := to_unsigned(integer(round(tmpR)), bits);
1322	         return slv(retUnsigned);
1323	      end if;
1324	   end function adcConversion;
1325	
1326	   -----------------------------
1327	   -- gets a time ratio
1328	   -----------------------------
1329	   function getTimeRatio (T1, T2 : time) return natural is
1330	   begin
1331	      return natural(T1/T2);
1332	   end function;
1333	
1334	   function getTimeRatio (T1, T2 : real) return natural is
1335	   begin
1336	      return natural(ROUND(abs(T1/T2)));
1337	   end function;
1338	
1339	   ---------------------------------------------------------------------------------------------------------------------
1340	   -- Convert a frequency to a period (time).
1341	   ---------------------------------------------------------------------------------------------------------------------
1342	-- pragma translate_off
1343	
1344	   function toTime(f : frequency) return time is
1345	   begin
1346	      return(1.0 sec / (f/Hz));
1347	   end function;
1348	
1349	--pragma translate_on
1350	
1351	   -----------------------------
1352	   -- Mux a SlVectorArray into an SLV
1353	   -----------------------------
1354	   function muxSlVectorArray (vec             : SlVectorArray;
1355	                              addr            : natural;
1356	                              allowOutOfRange : boolean := false)
1357	      return slv is
1358	      variable retVar : slv(vec'range(2));
1359	   begin
1360	      -- Check the limit of the address
1361	      if (addr < vec'length(1)) or (allowOutOfRange = false) then
1362	         for i in vec'range(2) loop
1363	            retVar(i) := vec(addr, i);
1364	         end loop;
1365	      else
1366	         retVar := (others => '0');
1367	      end if;
1368	      return retVar;
1369	   end function;
1370	
1371	   procedure assignSlv (
1372	      i      : inout integer;
1373	      vector : inout slv;
1374	      value  : in    slv)
1375	   is
1376	      variable low : integer;
1377	   begin
1378	      low                    := i;
1379	      i                      := i+value'length;
1380	      vector(i-1 downto low) := value;
1381	   end procedure assignSlv;
1382	
1383	   procedure assignSlv (
1384	      i      : inout integer;
1385	      vector : inout slv;
1386	      value  : in    sl)
1387	   is
1388	   begin
1389	      vector(i) := value;
1390	      i         := i+1;
1391	   end procedure assignSlv;
1392	
1393	   procedure assignRecord (
1394	      i      : inout integer;
1395	      vector : in    slv;
1396	      value  : inout slv)
1397	   is
1398	      variable low : integer;
1399	   begin
1400	      low   := i;
1401	      i     := i+value'length;
1402	      value := vector(i-1 downto low);
1403	   end procedure assignRecord;
1404	
1405	   procedure assignRecord (
1406	      i      : inout integer;
1407	      vector : in    slv;
1408	      value  : inout sl)
1409	   is
1410	   begin
1411	      value := vector(i);
1412	      i     := i+1;
1413	   end procedure assignRecord;
1414	
1415	   -- Resize an SLV, either by trimming or padding upper bits
1416	   function resize (vec : slv; newSize : integer; pad : sl := '0') return slv is
1417	      variable ret : slv(newSize-1 downto 0);
1418	      variable tmp : slv(vec'length-1 downto 0);
1419	      variable top : integer;
1420	   begin
1421	      ret               := (others => pad);
1422	      tmp               := vec;         -- handles ranges that arent x:0
1423	      top               := minimum(newSize, vec'length) - 1;
1424	      ret(top downto 0) := tmp(top downto 0);
1425	      return ret;
1426	   end function;
1427	
1428	   function resize (str : string; newSize : integer; pad : character := nul) return string is
1429	      variable ret : string(1 to newSize);
1430	      variable tmp : string(1 to str'length);
1431	      variable top : integer;
1432	   begin
1433	      ret           := (others => pad);
1434	      tmp           := str;
1435	      top           := minimum(newSize, str'length);
1436	      ret(1 to top) := tmp(1 to top);
1437	      return ret;
1438	   end function resize;
1439	
1440	   -- Match Functions
1441	   function StdMatch (L, R : std_ulogic) return boolean is
1442	   begin
1443	      return std_match(L, R);
1444	   end function StdMatch;
1445	
1446	   function StdMatch (L, R : unsigned) return boolean is
1447	   begin
1448	      return std_match(L, R);
1449	   end function StdMatch;
1450	
1451	   function StdMatch (L, R : signed) return boolean is
1452	   begin
1453	      return std_match(L, R);
1454	   end function StdMatch;
1455	
1456	   function StdMatch (L, R : slv) return boolean is
1457	   begin
1458	      return std_match(L, R);
1459	   end function StdMatch;
1460	
1461	
1462	   function toBuildInfo (din : slv) return BuildInfoRetType is
1463	      variable ret : BuildInfoRetType;
1464	   --variable i   : natural;
1465	   begin
1466	      for i in 0 to 255 loop
1467	         ret.buildString(i/4)(8*(i mod 4)+7 downto 8*(i mod 4)) := din(2047-(8*i) downto 2040-(8*i));
1468	      end loop;
1469	      ret.fwVersion := din(2079 downto 2048);
1470	      ret.gitHash   := din(2239 downto 2080);
1471	      return ret;
1472	   end function;
1473	
1474	   function toSlv (din : BuildInfoRetType) return BuildInfoType is
1475	      variable ret : BuildInfoType;
1476	   begin
1477	      for i in 0 to 255 loop
1478	         ret(2047-(8*i) downto 2040-(8*i)) := din.buildString(i/4)(8*(i mod 4)+7 downto 8*(i mod 4));
1479	      end loop;
1480	      ret(2079 downto 2048) := din.fwVersion;
1481	      ret(2239 downto 2080) := din.gitHash;
1482	      return ret;
1483	   end function toSlv;
1484	
1485	end package body StdRtlPkg;
